-- ============================================
-- Legislacao full-site: erika-hilton / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/220645
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = erika-hilton-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 122 rows Camara legacy existentes, somente 51
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=220645, tipo Deputado(a), ordemAssinatura=1.
-- 71 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'erika-hilton';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'erika-hilton: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 122 THEN
    RAISE EXCEPTION 'Pre-condicao erika-hilton: esperadas 122 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('2609012', '2609017', '2609013', '2604723', '2601395', '2600971', '2600188', '2600153', '2580804', '2577549', '2573705', '2571006', '2594742', '2584060', '2576773', '2570924', '2585403', '2576177', '2573351', '2570847', '2578200', '2589995', '2584232', '2578195', '2570208', '2584218', '2617422', '2620814', '2609024', '2570207', '2613136', '2612399', '2609119', '2596424', '2584054', '2620430', '2619274', '2619149', '2618980', '2618829', '2618786', '2618628', '2618573', '2603928', '2585266', '2620145', '2619159', '2618853', '2618787', '2618630', '2618575');
  IF target_present <> 51 THEN
    RAISE EXCEPTION 'Pre-condicao erika-hilton: esperadas 51 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('2609012', '2609017', '2609013', '2604723', '2601395', '2600971', '2600188', '2600153', '2580804', '2577549', '2573705', '2571006', '2594742', '2584060', '2576773', '2570924', '2585403', '2576177', '2573351', '2570847', '2578200', '2589995', '2584232', '2578195', '2570208', '2584218', '2617422', '2620814', '2609024', '2570207', '2613136', '2612399', '2609119', '2596424', '2584054', '2620430', '2619274', '2619149', '2618980', '2618829', '2618786', '2618628', '2618573', '2603928', '2585266', '2620145', '2619159', '2618853', '2618787', '2618630', '2618575')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'erika-hilton-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao erika-hilton: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao erika-hilton: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

